#!/usr/bin/env python3
# -*- coding: utf-8 -*-
"""Modernized Climate Data Analysis Script (Python 3).

Reads climate temperature data with pandas and reports the mean
temperature for each station.
"""

import configparser
from pathlib import Path

import numpy as np
import pandas as pd

BASE_DIR = Path(__file__).resolve().parent / "climate_analyzer"
DATA_PATH = BASE_DIR / "sample_data" / "climate_data.csv"
CONFIG_PATH = BASE_DIR / "config.ini"


class ClimateAnalyzer:
    """Analyze climate temperature data for multiple stations."""

    def __init__(self, config_path: Path = CONFIG_PATH) -> None:
        self.config = configparser.ConfigParser()
        if Path(config_path).exists():
            self.config.read(config_path, encoding="utf-8")

    def load_temperature_data(self, filename: Path) -> pd.DataFrame:
        """Load temperature data from a UTF-8 encoded CSV file."""
        return pd.read_csv(
            filename,
            encoding="utf-8",
            parse_dates=["date"],
        )

    def calculate_anomalies(self, temperature_series: pd.Series) -> np.ndarray:
        """Calculate temperature anomalies relative to the series mean."""
        values = np.asarray(temperature_series, dtype=float)
        return values - values.mean()

    def run_analysis(self) -> None:
        """Main analysis pipeline."""
        print("Starting climate analysis...")

        data = self.load_temperature_data(DATA_PATH)

        for station, group in data.groupby("station_id"):
            mean_temp = group["temperature"].mean()
            print(f"Station {station} mean temperature: {mean_temp:.1f}°C")

        print("Analysis completed successfully!")


def main() -> None:
    analyzer = ClimateAnalyzer()
    analyzer.run_analysis()


if __name__ == "__main__":
    main()

